import pytest
import requests

def test_unauthorised_caller_cannot_acknowledge_alert(
    active_alert_id, auth_token, base_url
):
    url = f"{base_url}/alerts/{active_alert_id}"
    payload = {"action": "confirm"}

    resp = requests.patch(url, json=payload)  # no auth header

    assert resp.status_code == 401, f"Expected 401, got {resp.status_code}: {resp.text}"

    get_resp = requests.get(
        url, headers={"Authorization": f"Bearer {auth_token}"}
    )
    assert get_resp.status_code == 200
    assert get_resp.json()["alert"]["status"] == "ACTIVE"

