import pytest
import requests

def test_exceeded_rate_limit_on_alert_acknowledgement_returns_429(
    active_alert_id, auth_token, base_url, rate_limit_threshold
):
    url = f"{base_url}/alerts/{active_alert_id}"
    headers = {"Authorization": f"Bearer {auth_token}"}
    payload = {"action": "confirm"}

    last_resp = None
    for i in range(rate_limit_threshold + 1):
        last_resp = requests.patch(url, json=payload, headers=headers)
        if last_resp.status_code == 429:
            break

    assert last_resp is not None
    assert last_resp.status_code == 429, (
        f"Expected 429 after exceeding rate limit, got {last_resp.status_code}: {last_resp.text}"
    )
    body = last_resp.json()
    assert "rate" in body.get("error", {}).get("message", "").lower() or \
           body.get("error", {}).get("code") == "RATE_LIMIT_EXCEEDED"

