):
    url = f"{base_url}/alerts/{active_alert_id_insufficient_funds_account}"
    headers = {"Authorization": f"Bearer {auth_token_insufficient_funds}"}
    payload = {"action": "confirm"}

    resp = requests.patch(url, json=payload, headers=headers)

    assert resp.status_code == 200, (
        f"Expected 200 for insufficient-funds account alert acknowledgement, "
        f"got {resp.status_code}: {resp.text}"
    )
    body = resp.json()
    assert body["alert"]["status"] == "CLOSED"
